package com.shecancode.product.config; import com.shecancode.product.model.*; import com.shecancode.product.repo.*; import org.springframework.boot.CommandLineRunner; import org.springframework.context.annotation.*; import java.math.BigDecimal; @Configuration public class SeedData { @Bean CommandLineRunner seed(CategoryRepository c, ProductRepository p){return a->{if(c.count()==0){Category e=c.save(new Category("Electronics","Electronic devices"));Category cl=c.save(new Category("Clothing","Clothes and shoes"));Category b=c.save(new Category("Books","Books"));Category h=c.save(new Category("Home","Home items"));p.save(new Product("Laptop","Portable computer",new BigDecimal("999.99"),10,e));p.save(new Product("Smartphone","Android smartphone",new BigDecimal("699.99"),15,e));p.save(new Product("Headphones","Wireless headphones",new BigDecimal("99.99"),20,e));p.save(new Product("T-Shirt","Cotton T-shirt",new BigDecimal("19.99"),30,cl));p.save(new Product("Shoes","Casual shoes",new BigDecimal("59.99"),18,cl));p.save(new Product("Programming Book","Learn Java",new BigDecimal("39.99"),12,b));p.save(new Product("Office Chair","Comfortable chair",new BigDecimal("149.99"),8,h));p.save(new Product("Cooking Pot","Kitchen pot",new BigDecimal("29.99"),14,h));}};} }